Crop.create!([
  {name: "Cubanelle Pepper", description: "The Cuban, Cubanelle, or Italian Frying pepper, is a sweet Capsicum annuum cultivar popular in Cuban, Dominican, Puerto Rican, and Italian cuisine. Cubanelles have 2-3 lobes and are 12-18cm long. They have more flavor, thinner flesh, and a lower water content than bell peppers. Cubanelles ripen from light yellow-green to orange-red, but are commonly harvested at yellow-green to be roasted or fried. They have a Scoville rating of 1,000 units.", sun_requirements: "Full Sun", sowing_method: "Direct seed indoors, transplant seedlings outside after hardening off", height: 75, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/59d7ed032af727000400000a.jpg?1507323137", growing_days: nil, day_planted: "2020-06-16T15:23:32.884Z", number_planted: 4, current_height: 26, quantity_returned: 5, status_of_plant: "needs more water daily", garden_id: 1},
  {name: "Eggplant", description: "Eggplants commonly are egg-shaped with glossy black skin, but can come in a variety of other shapes and colors. They can be white, yellow, and pale to deep purple. Some are as small as goose eggs. The 'Rosa Bianca' cultivar is squat and round, while Asian cultivars can be long and thin. Eggplant stems are often spiny and their flowers range from white to purple. \n\nTheir flesh is generally white with a meaty texture and small seeds in the center. They are delicious grilled, roasted, in soups and stews, and breaded and fried.", sun_requirements: "Full Sun", sowing_method: "Sow seeds indoors and transplant out, or plant nursery seedlings", height: 50, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b79ddfe8d75000300038a.jpg?1466661339", growing_days: nil, day_planted: "2020-06-16T15:23:47.816Z", number_planted: 4, current_height: 15, quantity_returned: 20, status_of_plant: "Doing well", garden_id: 1},
  {name: "Rice", description: "Rice is the seed of the grass species Oryza sativa. It is a cereal grain that can come in many shapes, colors, and sizes. Rice requires ample water and is labor-intensive to cultivate. Water-controlling terrace systems enable it to be grown almost anywhere. The traditional method of cultivating rice is to flood the fields during or after setting the young seedlings. Rice can be grown without flooding, but flooding simplifies weed and pest control.", sun_requirements: "Full Sun", sowing_method: "Seedlings", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/58e330a94bca6f00040000b8.jpg?1491284134", growing_days: nil, day_planted: "2020-06-16T15:23:58.219Z", number_planted: 3, current_height: 123, quantity_returned: nil, status_of_plant: "doing great today", garden_id: 1},
  {name: "Corn", description: "Corn is a large grain plant, or tall grass, first domesticated about 10,000 years ago by indigenous peoples in Southern Mexico. The leafy stalk produces ears after pollination. Depending on the variety, the corn can be eaten fresh, or dried and ground into cornmeal.", sun_requirements: "Full Sun", sowing_method: "Direct seed outdoors", height: 290, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b77b7fe8d750003000300.jpg?1466660787", growing_days: nil, day_planted: "2020-06-16T19:37:07.478Z", number_planted: 2, current_height: 80, quantity_returned: nil, status_of_plant: "Will be a couple more weeks before I see any return on these", garden_id: 1},
  {name: "Purple Potato", description: "Purple potatoes are a type of potato with purple skin and white to purple flesh. Common varieties include Magic Molly, Purple Majesty, Adirondack Blue, Peter Wilcox (yellow flesh), and Harvest Moon (purple and white swirled skin with white flesh). Flavor and texture vary based on variety.", sun_requirements: "Full Sun", sowing_method: "Direct seed cut tubers with at least one \"eye\" per piece.", height: 50, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/58c3ba257b12f80004000008.jpg?1489222179", growing_days: nil, day_planted: "2020-06-16T21:45:47.598Z", number_planted: 7, current_height: 10, quantity_returned: nil, status_of_plant: "Buried deep will be ready to pick in a few months", garden_id: 1},
  {name: "Potato", description: "Potatoes are starchy root vegetables in the Solanaceae, or Nightshade, family, which also includes tomatoes, eggplants, and peppers. They originated in South America, and spread to become a worldwide staple. The leaves and fruit are usually poisonous and the stem tuber is the only edible part once it is cooked. The potato can be cooked in many ways, brewed into alcohol, and also used as the basis for creating bioplastics. More growing information is available in individual species entries.", sun_requirements: "Full Sun", sowing_method: "Direct seed outdoors after last frost. Each piece must have one eye.", height: 60, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/551dbd5a3732390003600100.jpg?1428012376", growing_days: nil, day_planted: "2020-06-16T22:59:33.811Z", number_planted: 4, current_height: 0, quantity_returned: nil, status_of_plant: "Can't wait to dig these bad boys up", garden_id: 1},
  {name: "Bonnie Cucumber Heirloom Straight Eight", description: "Cucumbers are the fruit of a creeping vine. They are generally oblong and have a high water content. Their edible skin is often green but can also be yellow, white, or striped. \n\nThe vine can be left to spread along the ground, or it can be trained to a trellis. The vine's large leaves hide the cucumbers and shade them. There are three main varieties of cucumber: slicing, pickling, and seedless.", sun_requirements: "Full Sun", sowing_method: "Direct seed outdoors in groups of 2-3, 1/2\" deep. Thin to 1 plant.", height: 20, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b7843fe8d750003000305.jpg?1466660929", growing_days: nil, day_planted: "2020-06-16T23:00:02.400Z", number_planted: 3, current_height: 123, quantity_returned: nil, status_of_plant: "doing great today", garden_id: 1},
  {name: "Wine Grape", description: "", sun_requirements: "", sowing_method: "", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/551dcb883732390003780100.jpg?1428016007", growing_days: nil, day_planted: "2020-06-16T23:00:29.310Z", number_planted: 2, current_height: 46, quantity_returned: 12, status_of_plant: "Needs to be watered more frequently", garden_id: 1},
  {name: "Banana", description: "The banana is a tropical perennial herb that produces edible fruits. There are many different species of banana within the Musa genus. Banana trees can be grown outdoors in tropic and subtropical climates, and indoors in northern areas. Bananas like company: plant them in blocks or clumps so they can shelter one another from wind and build humidity. The best bananas will grow towards the middle of the clump. Hot, dry air and temperatures below 0ºC will seriously harm or kill a banana tree.", sun_requirements: "Full Sun", sowing_method: "Rhizome or sucker", height: 4000, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/5939f8db01f879000400000d.jpg?1496971476", growing_days: nil, day_planted: "2020-06-16T23:00:44.248Z", number_planted: 2, current_height: 123, quantity_returned: nil, status_of_plant: "doing great today", garden_id: 1},
  {name: "Almond", description: "The almond is a deciduous tree that grows well in Mediterranean climates. It has white to pale flowers that appear before the leaves in early spring. Trees begin producing fruit within 2 to 4 years of being transplanted.", sun_requirements: "Full Sun", sowing_method: "Bare root tree", height: 400, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/593882406d9b0f00040000c7.jpg?1496875579", growing_days: nil, day_planted: "2020-06-16T23:01:00.496Z", number_planted: 2, current_height: 123, quantity_returned: nil, status_of_plant: "doing great today", garden_id: 1},
  {name: "Avocado", description: "The avocado is a tree native to South Central America that produces large edible berries with rippled green to black skin that are egg or pear-shaped. There are three main groups of avocado: Mexican, Guatemalan, and West Indian, with Mexican avocados being the most cold-tolerant. Avocados are a subtropical species and need a frost-free climate with little wind. They will not produce fruit outside of tropical climates, but they can be grown as evergreen ornamentals. Avocados grown from seed rarely produce fruit because they are only partially self-pollinating. For a fruiting tree, plant a grafted sapling in a subtropical climate.", sun_requirements: "Full Sun", sowing_method: "Grafted sapling", height: 2000, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b7393fe8d7500030002ea.jpg?1466659729", growing_days: nil, day_planted: "2020-06-16T23:01:10.325Z", number_planted: 3, current_height: 123, quantity_returned: nil, status_of_plant: "doing great today", garden_id: 1},
  {name: "Purslane", description: "Purslane is a fast-growing succulent herb that is native to Asia but has since naturalized throughout the world. The plant has red to purple stems that radiate from a central taproot, fleshy green leaves, and yellow flowers. The stems are somewhat upright, but spread to create a mat of foliage. Leaves and stems have a sweet, acid-like flavor similar to spinach and are high in omega-3 fatty acids, Vitamins A, C, and B, iron, magnesium, calcium, and potassium. Harvest plants before they flower and add to salads, sandwiches, sauté, or make into pesto. Purslane can become VERY invasive because it spreads through stem pieces and a single plant can produce 240,000 seeds that are viable for 5-40 years. Container growing is strongly recommended to limit the spread of stem cuttings. Be sure to harvest plants before they flower and set seed.", sun_requirements: "Full Sun", sowing_method: "Direct seed cuttings or seeds outdoors on surface of soil after last frost", height: 10, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/5a134c98956ccf0004000007.jpg?1511214228", growing_days: nil, day_planted: "2020-06-17T02:14:05.543Z", number_planted: 2, current_height: 1234, quantity_returned: nil, status_of_plant: "just one", garden_id: 2},
  {name: "Aloe Vera", description: "Aloe Vera is an evergreen succulent with thick, fleshy leaves with serrated edges. It can be grown outdoors in USDA Plant Hardiness Zones 9-11 or indoors anywhere. Like all succulents, Aloe Vera does best with bright light and in arid conditions. Aloe is often grown for ornamental and medicinal uses: the juice from it's leaves is frequently applied to sunburns and other wounds.", sun_requirements: "Full Sun", sowing_method: "Cuttings or \"pups\"", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/5939d1c501f8790004000000.jpg?1496961474", growing_days: nil, day_planted: "2020-06-17T02:14:12.918Z", number_planted: 2, current_height: 9182, quantity_returned: nil, status_of_plant: "hello there", garden_id: 2},
  {name: "Brussels Sprouts", description: "Brussels sprouts grow on the sides of stalks up to 91cm tall. The stalks are covered with leaves and the sprouts look like miniature cabbages. They are a cool weather crop and are delicious roasted.", sun_requirements: "Full Sun", sowing_method: "Sow seeds indoors, harden off seedlings before transplanting outdoors", height: 91, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/551e27c53732390003830100.jpg?1428039620", growing_days: nil, day_planted: "2020-06-17T21:03:02.734Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 2},
  {name: "Corn", description: "Corn is a large grain plant, or tall grass, first domesticated about 10,000 years ago by indigenous peoples in Southern Mexico. The leafy stalk produces ears after pollination. Depending on the variety, the corn can be eaten fresh, or dried and ground into cornmeal.", sun_requirements: "Full Sun", sowing_method: "Direct seed outdoors", height: 290, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b77b7fe8d750003000300.jpg?1466660787", growing_days: nil, day_planted: "2020-06-18T04:59:04.276Z", number_planted: 13, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 4},
  {name: "Squash", description: "Squash is a genus of herbaceous vines that have large edible orange flowers that mature into gourds or cucurbits. Squash are commonly divided into two main groups: summer and winter. Summer squash have shorter growing times, a bushy growth habit, tender skin, and are quite prolific. Common types include cucumbers, zucchini, and pattypan squash. Winter squash take longer to mature, have a more sprawling growth habit, and produce gourds with thicker skins that can be stored for a few months. Common winter squash are pumpkins, butternut squash, acorn, and delicata. Most squash transplant poorly. If starting from seed indoors, use peat pots that can be directly transplanted into the soil to reduce root disturbance. More growing information is available in individual species entries.", sun_requirements: "Full Sun", sowing_method: "Direct seed indoors or outdoors", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/54b4a9046130650002010000.jpg?1421125890", growing_days: nil, day_planted: "2020-06-18T05:01:18.389Z", number_planted: 2, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 4},
  {name: "Cactus", description: nil, sun_requirements: nil, sowing_method: nil, height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b7547fe8d7500030002f3.jpg?1466660165", growing_days: nil, day_planted: "2020-06-18T05:01:51.110Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 4},
  {name: "Peach", description: "The peach tree is a deciduous tree native to Northwest China that produces stone, or drupe, fruits. It belongs to the genus Prunus which includes the cherry, apricot, almond, and plum. The peach is classified with the almond in the subgenus Amygdalus because their stones are corrugated rather than smooth. Peaches and nectarines are the same species - nectarines have a recessive gene that makes their skin smooth rather than fuzzy. Cultivated peaches are divided into two groups: clingstones and freestones, depending on whether the flesh sticks to the stone or not. Peaches can have white or yellow fuzzy skin. Yellow peaches usually have an acidic tang coupled with sweetness. White peaches are very sweet with little acidity. Most cultivars require 500 hours of chilling around 0 to 10 °C during the winter, and hot temperatures in the summer to ripen fruit. Some varieties are self-pollinating, while others require pollination by a peach tree of another variety with the same bloom period within 50 feet. Peaches should be thinned to 7-12cm apart when fruit are 2-3cm in diameter to increase mature fruit size. Standard and dwarf rootstocks are available. Dwarf trees can grow to 3 meters, standard to 4.5 meters. Depending on the size chosen, the tree will bear fruit within 2-4 years of planting.", sun_requirements: "Full Sun", sowing_method: "Transplant bare-root plant", height: 1000, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/59b1a6e444d62e0004000006.jpg?1504814816", growing_days: nil, day_planted: "2020-06-18T05:02:08.849Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 4},
  {name: "Lemon balm", description: "A perennial herb in the mint family that flowers during the summer and gives off a strong lemon scent.", sun_requirements: "Full Sun", sowing_method: "Sow seeds, spreads vegetatively.", height: 120, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/54f51fb83730360003000000.jpg?1425350578", growing_days: nil, day_planted: "2020-06-18T14:51:05.893Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 6},
  {name: "Rice", description: "Rice is the seed of the grass species Oryza sativa. It is a cereal grain that can come in many shapes, colors, and sizes. Rice requires ample water and is labor-intensive to cultivate. Water-controlling terrace systems enable it to be grown almost anywhere. The traditional method of cultivating rice is to flood the fields during or after setting the young seedlings. Rice can be grown without flooding, but flooding simplifies weed and pest control.", sun_requirements: "Full Sun", sowing_method: "Seedlings", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/58e330a94bca6f00040000b8.jpg?1491284134", growing_days: nil, day_planted: "2020-06-18T14:51:19.384Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 6},
  {name: "Avocado", description: "The avocado is a tree native to South Central America that produces large edible berries with rippled green to black skin that are egg or pear-shaped. There are three main groups of avocado: Mexican, Guatemalan, and West Indian, with Mexican avocados being the most cold-tolerant. Avocados are a subtropical species and need a frost-free climate with little wind. They will not produce fruit outside of tropical climates, but they can be grown as evergreen ornamentals. Avocados grown from seed rarely produce fruit because they are only partially self-pollinating. For a fruiting tree, plant a grafted sapling in a subtropical climate.", sun_requirements: "Full Sun", sowing_method: "Grafted sapling", height: 2000, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b7393fe8d7500030002ea.jpg?1466659729", growing_days: nil, day_planted: "2020-06-18T14:51:30.226Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 6},
  {name: "Bonnie Cucumber Heirloom Straight Eight", description: "Cucumbers are the fruit of a creeping vine. They are generally oblong and have a high water content. Their edible skin is often green but can also be yellow, white, or striped. \n\nThe vine can be left to spread along the ground, or it can be trained to a trellis. The vine's large leaves hide the cucumbers and shade them. There are three main varieties of cucumber: slicing, pickling, and seedless.", sun_requirements: "Full Sun", sowing_method: "Direct seed outdoors in groups of 2-3, 1/2\" deep. Thin to 1 plant.", height: 20, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/576b7843fe8d750003000305.jpg?1466660929", growing_days: nil, day_planted: "2020-06-18T14:52:01.139Z", number_planted: 2, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 6},
  {name: "Banana Pepper", description: "Banana peppers are Capsicum annuum cultivars that are curved like a banana and have a mild, tangy taste. They are often bright yellow, but can also be green, red, or orange. Mature, ripe peppers are sweeter than younger ones. Spicy varieties are called Hungarian wax peppers. Banana peppers are often confused with Pepperoncini, which are a separate cultivar of Capiscum annuum and Capsicum frutescens. Banana peppers can be eaten raw, stuffed, or pickled.", sun_requirements: "Full Sun", sowing_method: "Direct seed indoors, transplant seedlings outside after hardening off.", height: 60, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/593b2deaa2f58400040000ba.jpg?1497050597", growing_days: nil, day_planted: "2020-06-18T14:52:14.989Z", number_planted: 2, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 6},
  {name: "Bonnie Little Bing Compact Cherry Tomato", description: "The tomato is the fruit of the tomato plant, a member of the Nightshade family (Solanaceae). The fruit grows on a small compact bush.", sun_requirements: "Full Sun", sowing_method: "Direct seed indoors, transplant seedlings outside after hardening off", height: 45, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/5dc3618ef2c1020004f936e4.jpg?1573085580", growing_days: 60, day_planted: "2020-06-18T15:14:52.447Z", number_planted: 5, current_height: 4, quantity_returned: 0, status_of_plant: "just planted doing great", garden_id: 7},
  {name: "Chili Pepper", description: "The chilli pepper (from Nahuatl chīlli) is the fruit of plants from the genus Capsicum which are members of the nightshade family, Solanaceae. Chilli peppers are widely used in many cuisines as a spice to add heat to dishes. The substances that give chilli peppers their intensity when ingested or applied topically are capsaicin and related compounds known as capsaicinoids.\n\nChilli peppers originated in Mexico. After the Columbian Exchange, many cultivars of chilli pepper spread across the world, used for both food and traditional medicine.", sun_requirements: "", sowing_method: "", height: nil, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/54ffd15f31343500038b0200.jpg?1426051420", growing_days: nil, day_planted: "2020-06-18T15:15:16.336Z", number_planted: 3, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 7},
  {name: "black beauty eggplant", description: "Rich, deep purplish black fruits can grow to enormous size. Tender & tasty at all stages. \nhttp://burpee.com/more/60324", sun_requirements: "Full Sun", sowing_method: "Start indoors in a warm, well-lighted area 8-10 weeks before last frost. Sow seeds in a seed starting formula in individual containers. Sow 1cm deep, firm lightly and keep evenly moist. Seedlings emerge 10-21 days.", height: 30, image_path: "https://s3.amazonaws.com/openfarm-project/production/media/pictures/attachments/5928ef56f55b2400040000b6.jpg?1495854927", growing_days: 74, day_planted: "2020-06-18T15:20:20.182Z", number_planted: 4, current_height: nil, quantity_returned: nil, status_of_plant: nil, garden_id: 1},
